document.addEventListener('DOMContentLoaded', function () {
  const nameTarget  = document.getElementById('showUserNameTarget');
  const nameWrapper = document.getElementById('showUserNameWrapper');
  const headerEl    = document.querySelector('.dt-emc-header');
  const userDashboard = document.querySelectorAll('.dds__user-dashboard');

     userDashboard.forEach(usercard => {
        const userInfo = usercard.querySelector('.dds__user-info');
    const userTitle = usercard.querySelector('.dds__user-title');
    const userCommunity = usercard.querySelector('.dds__community-text');



        function adjustTextColor() {
          const backgroundColor = window.getComputedStyle(usercard).backgroundColor;
          const rgb = backgroundColor.match(/\d+/g).map(Number);
          const brightness = (rgb[0] * 299 + rgb[1] * 587 + rgb[2] * 114) / 1000;

          if (brightness > 128) {
            if(userInfo){
              userInfo.classList.add('dark-text');
              userInfo.classList.remove('light-text');
            }
              if(userTitle){
              userTitle.classList.add('dark-text');
              userTitle.classList.remove('light-text');
            }
              if(userCommunity){
              userCommunity.classList.add('dark-text');
              userCommunity.classList.remove('light-text');
            }

          } else {
            if (userInfo) {
                    userInfo.classList.add('light-text');
                    userInfo.classList.remove('dark-text');
                }
              if (userTitle) {
                    userTitle.classList.add('light-text');
                    userTitle.classList.remove('dark-text');
                }
              if (userCommunity) {
                    userCommunity.classList.add('light-text');
                    userCommunity.classList.remove('dark-text');
                }

            }
          }


        adjustTextColor();
      });

  if (nameTarget && nameWrapper && headerEl) {
    const audtypeAttr = headerEl.getAttribute('data-audtype') || '';
    const audtype = audtypeAttr.toLowerCase();
    const username = headerEl.getAttribute('data-username');

    if (audtype !== 'guest' && username && username.trim() !== '') {
      nameTarget.textContent = username.trim();
    } else {

      nameWrapper.style.display = 'none';
    }
  }
     const creditsTarget = document.getElementById('trainingCreditsCount');
  if (creditsTarget) {
    const tcredits = headerEl.getAttribute('data-tcredits');
    if (tcredits && tcredits.trim() !== '') {
      creditsTarget.textContent = tcredits.trim();
    }
  }
});

