let audiencewrapper = document.querySelectorAll(".jq-audiencewrapper");
let bodyTag = document.querySelector(".dt-emc-header");
let audienceType = bodyTag.getAttribute("data-audtype") == "ExternalX" ? "customer" : bodyTag.getAttribute("data-audtype");
let  displayClassName = "display-" + audienceType.toLowerCase() + "-content";
if(audienceType != "Guest" && audienceType != "Internal") {
  let lldisplay = bodyTag.getAttribute("data-lldisplay") == "true" ?  displayClassName = "display-" + audienceType.toLowerCase() + "lh-content" :  displayClassName = "display-" + audienceType.toLowerCase() + "-content";
  let personType = bodyTag.getAttribute("data-personType") != null ?  displayClassName = "display-techdirect-content" : "";
}
if (window.location.pathname.includes("/unauthorized.html")) {
	var referrerUrl = document.referrer;

    if (referrerUrl && referrerUrl.includes("/dsp")) {
        displayClassName = "display-techdirect-content";
    }
}
if((audienceType != "" || audienceType != null) && (audiencewrapper.length > 0)){
  audiencewrapper.forEach(element => {
    const classList = Array.from(element.classList);
    const lowerCaseClassList = classList.map((className) => className.toLowerCase());
    const hasClass = lowerCaseClassList.includes( displayClassName);
    if(hasClass){
      element.classList.remove('dds__d-none');
    } else{
      element.innerHTML = ""
    }
  })
}
const carouselBanner = document.querySelector('.carouselbanner');
if(carouselBanner != null){
let parentNode = carouselBanner.parentNode;
     	while (parentNode) {
           if (parentNode.classList.contains('jq-audiencewrapper')) {
                parentNode.style.display = 'contents';
                break;
           }
           parentNode = parentNode.parentNode;
     	}
}

